import { getClient } from "@/sanity/client";
import { homeQuery } from "@/sanity/queries";
import Image from "next/image";

export default async function Home() {
  let data: any = null;
  try {
    const client = getClient();
    data = await client.fetch(homeQuery, {}, { next: { revalidate: 60 } });
  } catch {
    // ignore
  }

  const title = "Zesen 的作品集";
  const subtitle = "UI/UX 设计师 | 项目与工作经历";
  const projects = data?.projects ?? [];
  const experience = data?.experience ?? [];

  return (
    <main className="min-h-screen px-6 py-16">
      <section className="max-w-4xl mx-auto text-center space-y-3">
        <h1 className="text-4xl font-semibold">{title}</h1>
        <p className="text-neutral-600">{subtitle}</p>
      </section>

      <section className="max-w-6xl mx-auto mt-12 grid gap-6 grid-cols-1 sm:grid-cols-2 lg:grid-cols-3">
        {projects.length === 0 ? (
          <div className="col-span-full text-center text-neutral-500">
            暂无作品，稍后在 Sanity Studio 中添加 Project 即可显示。
          </div>
        ) : (
          projects.map((p: any) => (
            <article
              key={p?.slug?.current ?? p.title}
              className="rounded-lg border bg-white/50 overflow-hidden"
            >
              {p?.coverImage && (
                <Image
                  src={p.coverImage.asset.url ?? ""}
                  alt={p.title}
                  width={800}
                  height={600}
                  className="w-full h-48 object-cover"
                />
              )}
              <div className="p-4 space-y-2">
                <h3 className="font-medium">{p.title}</h3>
                {p.summary && (
                  <p className="text-sm text-neutral-600">{p.summary}</p>
                )}
              </div>
            </article>
          ))
        )}
      </section>

      <section className="max-w-4xl mx-auto mt-16">
        <h2 className="text-2xl font-semibold mb-6">工作经历</h2>
        {experience.length === 0 ? (
          <p className="text-neutral-500">暂无工作经历，稍后在 Studio 中添加 Experience。</p>
        ) : (
          <ul className="space-y-4">
            {experience.map((e: any, idx: number) => (
              <li key={idx} className="border rounded-lg p-4 bg-white/50">
                <div className="flex items-center justify-between">
                  <span className="font-medium">{e.company}</span>
                  <span className="text-sm text-neutral-500">{e.period}</span>
                </div>
                <div className="text-sm text-neutral-700 mt-1">{e.role}</div>
                {e.description && (
                  <p className="text-sm text-neutral-600 mt-2">{e.description}</p>
                )}
              </li>
            ))}
          </ul>
        )}
      </section>
    </main>
  );
}
